// Some portions generated by Codex
package org.eclipse.rdf4j.spin.function;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.junit.jupiter.api.Test;

public class ConcatTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final Concat CONCAT = new Concat();

	@Test
	public void sameLanguageLiteralsPreserveLanguage() {
		Literal result = CONCAT.evaluate(VF, VF.createLiteral("a", "en"), VF.createLiteral("b", "en"));

		assertEquals("ab", result.getLabel());
		assertEquals("en", result.getLanguage().orElse(null));
		assertEquals(RDF.LANGSTRING, result.getDatatype());
	}

	@Test
	public void sameDirectedLanguageLiteralsPreserveBaseDirection() {
		Literal result = CONCAT.evaluate(VF, VF.createLiteral("a", "he", Literal.BaseDirection.RTL),
				VF.createLiteral("b", "he", Literal.BaseDirection.RTL));

		assertEquals("ab", result.getLabel());
		assertEquals("he", result.getLanguage().orElse(null));
		assertEquals(Literal.BaseDirection.RTL, result.getBaseDirection());
		assertEquals(RDF.DIRLANGSTRING, result.getDatatype());
	}

	@Test
	public void mixedBaseDirectionDropsLanguageMetadata() {
		Literal result = CONCAT.evaluate(VF, VF.createLiteral("a", "he", Literal.BaseDirection.RTL),
				VF.createLiteral("b", "he", Literal.BaseDirection.LTR));

		assertEquals("ab", result.getLabel());
		assertFalse(result.getLanguage().isPresent());
		assertEquals(Literal.BaseDirection.NONE, result.getBaseDirection());
		assertEquals(XSD.STRING, result.getDatatype());
	}
}
